#include <iostream>
#include <string>
#define MOD 1000000007
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        string a, b;
        cin >> a >> b;
        int n = a.size();
        long long dp[n + 1][2][2];
        dp[0][0][0] = 1;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 2; j++) {
                for (int k = 0; k < 2; k++) {
                    if (a[i] == '1' && b[i] == '1') {
                        dp[i + 1][j][k] = (dp[i + 1][j][k] + dp[i][j][k]) % MOD;
                        if (j == 0 && k == 0) {
                            dp[i + 1][1][1] = (dp[i + 1][1][1] + dp[i][j][k]) % MOD;
                        }
                    } else if (a[i] == '2' && b[i] == '2') {
                        dp[i + 1][j][k] = (dp[i + 1][j][k] + dp[i][j][k]) % MOD;
                        if (j == 0 && k == 0) {
                            dp[i + 1][1][1] = (dp[i + 1][1][1] + dp[i][j][k]) % MOD;
                        }
                    } else if (a[i] == '1' && b[i] == '2') {
                        dp[i + 1][1][0] = (dp[i + 1][1][0] + dp[i][j][k]) % MOD;
                        dp[i + 1][0][1] = (dp[i + 1][0][1] + dp[i][j][k]) % MOD;
                    } else if (a[i] == '2' && b[i] == '1') {
                        dp[i + 1][1][0] = (dp[i + 1][1][0] + dp[i][j][k]) % MOD;
                        dp[i + 1][0][1] = (dp[i + 1][0][1] + dp[i][j][k]) % MOD;
                    }
                }
            }
        }
        cout << dp[n][0][0] << endl;
    }
    return 0;
}

